<# .SYNOPSIS Offline regression for the shadow candidate dispatch gate. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..\..')).Path;$tmp=Join-Path $root '.qianlima\tmp';New-Item -ItemType Directory -Path $tmp -Force|Out-Null;$requestPath=Join-Path $tmp 'shadow-request.json';$registryPath=Join-Path $tmp 'shadow-registry.json';$sourceRegistry=Get-Content -LiteralPath (Join-Path $root '.qianlima\shadow-candidate-provider-registry.json') -Raw -Encoding UTF8|ConvertFrom-Json;$gate=Join-Path $PSScriptRoot 'invoke-shadow-candidate-dispatch-gate.ps1'
function Run($provider,$risk,$data,$calls,$cost,$latency,$approval,$enableDispatch,$enableProvider,$version){$registry=$sourceRegistry|ConvertTo-Json -Depth 10|ConvertFrom-Json;$registry.network_dispatch_enabled=$enableDispatch;$entry=@($registry.providers|?{$_.provider_id-eq$provider})|Select-Object -First 1;if($null-ne$entry){$entry.enabled=$enableProvider};[IO.File]::WriteAllText($registryPath,($registry|ConvertTo-Json -Depth 10),[Text.UTF8Encoding]::new($false));$req=[ordered]@{provider_id=$provider;task_id='shadow-task';risk_level=$risk;data_classification=$data;max_calls=$calls;max_cost_usd=$cost;max_latency_ms=$latency;task_approval_ref=$approval;model_version=$version;fusion_plan_ref='fusion:1';collaboration_contract_ref='collab:1';employee_id='employee-a';agent_id='agent-a';claim_pack_output_ref='claim-pack:a'};[IO.File]::WriteAllText($requestPath,($req|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false));$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $gate -RequestPath $requestPath -RegistryPath $registryPath -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$cases=[System.Collections.Generic.List[object]]::new();$a=Run missing L3 public 1 1 1000 approval $true $true v1;$b=Run openai-shadow-readonly L3 public 1 1 1000 approval $false $false v1;$c=Run openai-shadow-readonly L3 confidential_reference_only 1 1 1000 approval $true $true v1;$d=Run openai-shadow-readonly L4 public 1 1 1000 approval $true $true v1;$e=Run openai-shadow-readonly L3 public 2 2 200000 approval $true $true v1;$f=Run openai-shadow-readonly L3 internal_sanitized 1 1 120000 approval $true $true v1;$cases.Add([pscustomobject]@{name='unknown_provider_denied';passed=($a.code-ne0)});$cases.Add([pscustomobject]@{name='default_disabled_denied';passed=($b.code-ne0)});$cases.Add([pscustomobject]@{name='confidential_data_denied';passed=($c.code-ne0)});$cases.Add([pscustomobject]@{name='L4_shadow_dispatch_denied';passed=($d.code-ne0)});$cases.Add([pscustomobject]@{name='budget_overrun_denied';passed=($e.code-ne0)});$cases.Add([pscustomobject]@{name='eligible_preflight_still_makes_no_call';passed=($f.code-eq0-and$f.text-match'eligible_for_dispatch'-and$f.text-match'"external_call_made":\s+false')});$failed=@($cases|?{-not$_.passed});$result=[pscustomobject]@{passed=($failed.Count-eq0);cases=@($cases);external_calls=$false;permissions_granted=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Shadow candidate dispatch gate regression failed: '+(($failed.name)-join', '))}
